SELECT TOP (#{pageRows}) RowNum AS rowNum, 구직번호 AS participantJobNo, 이름 AS participantUserName, 성별 AS participantGender, 참여유형 AS participantPartType, 참여자 AS participantPartic, 생년월일 AS participantDob, 최근상담일 AS participantLastCons, 상담경과일 AS participantAdventCons, 진행단계 AS participantProgress, 초기상담일 AS participantInItCons, IAP수료일 AS participantIAPDate, IAP3개월일자 AS participantIAP3Month, IAP5개월일자 AS participantIAP5Month, IAP3개월여부 AS participantISIAP3Month, IAP5개월여부 AS participantISIAP5Month, 간접고용서비스 AS participantEmploymentService, 수당지급일 AS participantAllowanceDate, 구직만료일 AS participantJobEX, 기간만료일 AS participantEXPDate, 집중알선여부 AS participantISIntensiveMediation, 마감 AS participantClose FROM ( SELECT ROW_NUMBER() OVER (
) AS RowNum, A.구직번호, A.성별, B.이름, A.참여자, A.참여유형, CASE WHEN A.생년월일 > '1900-01-01' AND A.생년월일 <> '' THEN A.생년월일 END AS 생년월일, CASE WHEN A.최근상담일 > '1900-01-01' AND A.최근상담일 <> '' THEN A.최근상담일 END AS 최근상담일, CASE WHEN A.최근상담일 <> '' AND A.마감='false' THEN DATEDIFF(DAY, A.최근상담일, GETDATE()) END AS 상담경과일, A.진행단계, CASE WHEN A.초기상담일 > '1900-01-01' AND A.초기상담일 <> '' THEN A.초기상담일 END AS 초기상담일, CASE WHEN A.IAP수료일 > '1900-01-01' AND A.IAP수료일 <> '' THEN A.IAP수료일 END AS IAP수료일, CASE WHEN A.IAP3개월일자 > '1900-01-01' AND A.IAP3개월일자 <> '' AND 진행단계 <> 'IAP 전' THEN A.IAP3개월일자 END AS IAP3개월일자, CASE WHEN A.IAP5개월일자 > '1900-01-01' AND A.IAP5개월일자 <> '' AND 진행단계 <> 'IAP 전' THEN A.IAP5개월일자 END AS IAP5개월일자, A.IAP3개월여부, A.IAP5개월여부, A.간접고용서비스, CASE WHEN A.수당지급일 > '1900-01-01' AND 수당지급일 <> '' THEN A.수당지급일 END AS 수당지급일, CASE WHEN A.구직만료일 > '1900-01-01' AND A.구직만료일 <> '' THEN A.구직만료일 END AS 구직만료일, CASE WHEN A.기간만료일 > '1900-01-01' AND A.기간만료일 <> '' THEN A.기간만료일 END AS 기간만료일, A.집중알선여부, A.마감 FROM J_참여자관리 A JOIN J_참여자관리_로그인정보 B ON A.전담자_계정 = B.아이디 WHERE
) AS SUB_QUERY WHERE SUB_QUERY.RowNum>#{startPage} AND #{endPage} >= SUB_QUERY.RowNum

SELECT ISNULL(구직번호, '') AS participantJobNo, ISNULL(A.등록일, '') AS participantRegDate, ISNULL(이름, '') AS participantUserName, ISNULL(참여자, '') AS participantPartic, CASE WHEN 생년월일 >= DATEADD(YEAR, -100, GETDATE()) THEN 생년월일 END AS participantDob, ISNULL(성별, '') AS participantGender, ISNULL(참여유형, '') AS participantPartType FROM J_참여자관리 A LEFT JOIN J_참여자관리_로그인정보 B ON A.전담자_계정 = B.아이디 WHERE B.아이디 = #{participantUserid} and B.지점 = #{participantBranch}
AND 구직번호 IN
#{data}

