UPDATE J_참여자관리
SET 전담자_계정 = #{targetCounselorID},
메모 = CONCAT(메모, ',', CONVERT(nvarchar, GETDATE()), ' ', #{sourceCounselorID}, ' 상담사 데이터 이관'),
전담자_변경일 = GETDATE()
WHERE 전담자_계정 = #{sourceCounselorID}
AND 지점 = #{participantBranch}
AND 구직번호 IN

    #{data}

UPDATE
    J_참여자관리
set
    IAP3개월여부 = #{participantISIAP3Month},
    IAP5개월여부 = #{participantISIAP5Month}
WHERE
    구직번호 = #{participantJobNo}


            AND
            전담자_계정 = #{participantUserid}

mapper.select:
SELECT r.구직번호 as participantJobNo, r.기업명 as companyName, r.담당자명 as contactName, r.이메일 as contactEmail, r.비상연락처 as contactPhone, r.기타요청사항 as contactOther, r.상태 as status, r.등록일 as registrationDate, r.수정일 as modificationDate, p.참여자 as participantPartic, (SELECT TOP 1 희망직무 FROM J_참여자관리_희망직무 WHERE 구직번호 = p.구직번호 AND 희망순위 = 1) as participantJobWant, p.전담자_계정 as participantUserid, p.지점 as participantBranch, m.이름 as participantUserName FROM J_참여자관리_이력서요청양식 r LEFT JOIN J_참여자관리 p ON r.구직번호 = p.구직번호 LEFT JOIN J_참여자관리_로그인정보 m ON p.전담자_계정 = m.아이디
AND r.상태 = #{status}
AND r.등록일 >= #{searchStartDate}
AND r.등록일 <= #{searchEndDate}
AND r.기업명 LIKE '%' + #{companyName} + '%'
AND p.참여자 LIKE '%' + #{participantPartic} + '%'
AND p.전담자_계정 = #{participantUserid}
AND p.지점 = #{participantBranch}
ORDER BY r.등록일 DESC
OFFSET #{startPage} ROWS FETCH NEXT #{pageRows} ROWS ONLY

SELECT COUNT(*) as totalCount
FROM J_참여자관리_이력서요청양식 r
LEFT JOIN J_참여자관리 p ON r.구직번호 = p.구직번호


        AND r.상태 = #{status}


        AND r.등록일 >= #{searchStartDate}


        AND r.등록일 <= #{searchEndDate}


        AND r.기업명 LIKE '%' + #{companyName} + '%'


        AND p.참여자 LIKE '%' + #{participantPartic} + '%'


        AND p.전담자_계정 = #{participantUserid}


        AND p.지점 = #{participantBranch}

